WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/33.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/33.0/apex.js")}


try{ 
var sheet = sforce.connection.query("Select id,IP_Last_Consent_Requested__c,IP_Last_Consent_Requested_By__c from Contact where id='{!Contact.Id}'"); 

records = sheet.getArray("records"); 
var requestdate = records[0].IP_Last_Consent_Requested__c; 
var requestby =  records[0].IP_Last_Consent_Requested_By__c;

var checktime = new Date(requestdate);
var checkdate = checktime.toLocaleDateString();
var checktime = checktime.toLocaleTimeString() ;
var requestdateformula = checkdate + ' ' + checktime;

if(requestdate==null && requestby==null) 
{ 

var callresult = sforce.apex.execute("CandidateConsentcall","sendcall",{ConID:"{! 
Contact.Id}"});
if(callresult == 'Created' || callresult == 'Updated' || callresult == 'Duplicate')
{ 
var c= new sforce.SObject("Contact"); 
c.id="{!Contact.Id}";
c.IP_Last_Consent_Requested__c =  new Date(); 
var user = sforce.connection.getUserInfo(); 
c.IP_Last_Consent_Requested_By__c = "{!$User.FirstName}" + ' ' + "{!$User.LastName}"; 
var results= sforce.connection.update([c]); 
alert('Record sent to data store successfully');
}
else {
alert('Request could not be sent to data store as : '+callresult);
} 
window.location.reload(); 
} 
else
{
var x = confirm('Consent for this Candidate was last requested on '+ requestdateformula  + ' by ' +requestby); 
if(x==true) 
{ 
var callresult = sforce.apex.execute("CandidateConsentcall","sendcall",{ConID:"{! 
Contact.Id}"});
if(callresult == 'Created' || callresult == 'Updated' || callresult == 'Duplicate')
{
var c= new sforce.SObject("Contact"); 
c.id="{!Contact.Id}";

c.IP_Last_Consent_Requested__c =  new Date(); 
var user = sforce.connection.getUserInfo(); 
c.IP_Last_Consent_Requested_By__c = "{!$User.FirstName}" + ' ' + "{!$User.LastName}"; 
var results= sforce.connection.update([c]); 
alert('Record sent to data store successfully');
}
else {
alert('Request could not be sent to data store as : '+callresult);
} 
window.location.reload(); 
} 
else 
{ 
window.location.reload(); 
}
}
}
catch(e){ 
alert( 
"An unexpected Error has Occurred. Error: " + 
e 
); 
}
